给这个 Python 函数生成 pytest 测试：

def calculate_discount(price: float, user_tier: str, is_member: bool) -> float:
    if price <= 0:
        raise ValueError('price must be positive')
    if user_tier not in ('bronze', 'silver', 'gold'):
        raise ValueError('invalid user tier')
    discount = 0.0
    if user_tier == 'gold':
        discount = 0.20
    elif user_tier == 'silver':
        discount = 0.10
    elif user_tier == 'bronze':
        discount = 0.05
    if is_member:
        discount += 0.05
    return price * (1 - min(discount, 0.25))

