给这个 TypeScript 函数写 Vitest 单元测试：

async function transferMoney(
  fromAccountId: string,
  toAccountId: string,
  amount: number,
  accountRepo: AccountRepository
): Promise<Transaction> {
  if (amount <= 0) throw new InvalidAmountError('amount must be positive')
  const from = await accountRepo.findById(fromAccountId)
  if (!from) throw new AccountNotFoundError(fromAccountId)
  const to = await accountRepo.findById(toAccountId)
  if (!to) throw new AccountNotFoundError(toAccountId)
  if (from.balance < amount) throw new InsufficientBalanceError()
  from.balance -= amount
  to.balance += amount
  await accountRepo.save(from)
  await accountRepo.save(to)
  return { fromAccountId, toAccountId, amount, createdAt: new Date() }
}

Write Rust unit tests for this function:

pub fn create_user(
    name: &str,
    email: &str,
    age: u32,
    repo: &impl UserRepository,
) -> Result<User, UserError> {
    if name.trim().is_empty() {
        return Err(UserError::NameRequired);
    }
    if !email.contains('@') || email.trim().is_empty() {
        return Err(UserError::EmailInvalid);
    }
    if age < 1 || age > 150 {
        return Err(UserError::AgeInvalid);
    }
    let user = User { id: Uuid::new_v4().to_string(), name: name.to_string(), email: email.to_string(), age };
    repo.save(&user).map_err(|_| UserError::SaveFailed)?;
    Ok(user)
}

Write Zig unit tests for this function:

pub fn create_user(
    name: []const u8,
    email: []const u8,
    age: u32,
    repo: UserRepository,
) UserError!User {
    if (name.len == 0) return UserError.NameRequired;
    if (std.mem.indexOf(u8, email, "@") == null) return UserError.EmailInvalid;
    if (age < 1 or age > 150) return UserError.AgeInvalid;
    const user = User{ .name = name, .email = email, .age = age };
    repo.save(user) catch return UserError.SaveFailed;
    return user;
}
